//! Hybrid Hope Jar — boot on E8, warm into a materialized hot cache.
//!
//! "If you can't beat them strictly, join them." The shootoff showed the
//! tradeoff clearly:
//!   * E8 jar  — instant cold start (3.3 KB, 31 µs load), 696M latent keys,
//!               but regenerates each key (~2 multiplies).
//!   * Monster — serves a 1.58 MB materialized table (no per-key work),
//!               but slow to load and capped at 196884 keys.
//!
//! The hybrid takes E8's bootstrap and Monster's warm-path speed: boot the
//! tiny latent E8 generator instantly, then memoize each slot the first time
//! it is discharged so repeat hits serve a materialized slice. Memory grows
//! only with the HOT working set — not the full 5.5 GB capacity, not even
//! the Monster jar's 1.58 MB unless that many distinct slots are touched.
//!
//! This is the startup/bootstrap win: a node is serving predictions ~18×
//! sooner than with the Monster jar, then converges to materialized-table
//! discharge speed on whatever slots it actually uses.

use crate::hope_jar_e8::{HopeJarE8, CARRIERS_PER_SLOT, COXETER_PHASES, ROOT_LANES};
use std::collections::HashMap;

/// E8 latent generator + a materialized hot-slot cache.
pub struct HybridHopeJar {
    e8: HopeJarE8,
    hot: HashMap<u16, Vec<u64>>,
    hits: u64,
    misses: u64,
}

impl HybridHopeJar {
    /// Wrap a (sealed) E8 jar. The hot cache starts empty — boot is just the
    /// E8 load, so time-to-first-key is the E8 cold-start, not the Monster's.
    pub fn new(e8: HopeJarE8) -> Self {
        Self {
            e8,
            hot: HashMap::new(),
            hits: 0,
            misses: 0,
        }
    }

    #[inline]
    fn slot(phase: u8, lane: u8) -> u16 {
        ((phase as usize % COXETER_PHASES) * ROOT_LANES + (lane as usize % ROOT_LANES)) as u16
    }

    /// Discharge a (phase, lane) slot. First touch regenerates from the E8
    /// generator and memoizes; repeat touches serve the materialized slice
    /// (Monster-style). The hot set is bounded by the distinct slots used.
    pub fn discharge(&mut self, phase: u8, lane: u8) -> &[u64] {
        let s = Self::slot(phase, lane);
        if self.hot.contains_key(&s) {
            self.hits += 1;
        } else {
            self.misses += 1;
            let v: Vec<u64> = self.e8.discharge_iter(phase, lane).collect();
            self.hot.insert(s, v);
        }
        self.hot.get(&s).map(|v| v.as_slice()).unwrap_or(&[])
    }

    /// O(1) point query — always served by the latent E8 generator (no
    /// per-slot materialization needed for a single key).
    pub fn predict(&self, shape_hash: u64) -> u64 {
        self.e8.predict(shape_hash)
    }

    /// Full latent capacity (|W(E8)|), independent of what's materialized.
    pub fn capacity(&self) -> u64 {
        self.e8.capacity()
    }

    pub fn hot_slots(&self) -> usize {
        self.hot.len()
    }
    /// Resident materialized keys = the hot working set (not the full cap).
    pub fn resident_keys(&self) -> usize {
        self.hot.values().map(|v| v.len()).sum()
    }
    pub fn hits(&self) -> u64 {
        self.hits
    }
    pub fn misses(&self) -> u64 {
        self.misses
    }
}

/// Arena variant: materialize hot slots into ONE contiguous buffer (like the
/// Monster jar's single table) instead of per-slot heap Vecs. The cached read
/// then serves a contiguous slice into the arena — same cache/prefetch
/// behavior as Monster — closing the ~2× raw-discharge gap that per-slot Vecs
/// leave open, while keeping E8's bootstrap/footprint wins.
pub struct ArenaHopeJar {
    e8: HopeJarE8,
    arena: Vec<u64>,
    offsets: HashMap<u16, usize>,
    hits: u64,
    misses: u64,
}

impl ArenaHopeJar {
    /// Wrap a sealed E8 jar. `budget_slots` pre-reserves the contiguous arena
    /// so materializing the hot working set never reallocates mid-flight.
    pub fn new(e8: HopeJarE8, budget_slots: usize) -> Self {
        Self {
            e8,
            arena: Vec::with_capacity(budget_slots * CARRIERS_PER_SLOT),
            offsets: HashMap::new(),
            hits: 0,
            misses: 0,
        }
    }

    #[inline]
    fn slot(phase: u8, lane: u8) -> u16 {
        ((phase as usize % COXETER_PHASES) * ROOT_LANES + (lane as usize % ROOT_LANES)) as u16
    }

    /// Discharge a slot as a contiguous slice into the shared arena. First
    /// touch regenerates and appends to the arena; repeat touches return the
    /// contiguous slice (Monster-style prefetchable read).
    pub fn discharge(&mut self, phase: u8, lane: u8) -> &[u64] {
        let s = Self::slot(phase, lane);
        let off = match self.offsets.get(&s) {
            Some(&o) => {
                self.hits += 1;
                o
            }
            None => {
                self.misses += 1;
                let keys: Vec<u64> = self.e8.discharge_iter(phase, lane).collect();
                let o = self.arena.len();
                self.arena.extend_from_slice(&keys);
                self.offsets.insert(s, o);
                o
            }
        };
        &self.arena[off..off + CARRIERS_PER_SLOT]
    }

    pub fn predict(&self, shape_hash: u64) -> u64 {
        self.e8.predict(shape_hash)
    }
    pub fn capacity(&self) -> u64 {
        self.e8.capacity()
    }
    pub fn resident_keys(&self) -> usize {
        self.arena.len()
    }
    pub fn hot_slots(&self) -> usize {
        self.offsets.len()
    }
}
